 3→export const formatCurrency = (amount: number): string =>
 4→  new Intl.NumberFormat('en-IN', {
 5→    style: 'currency',
 6→    currency: 'INR',
 7→    maximumFractionDigits: 0,
 8→  }).format(amount);
 9→
10→export const formatCurrencyShort = (amount: number): string => {
11→  const abs = Math.abs(amount);
12→  if (abs >= 1_00_00_000) return `${(amount / 1_00_00_000).toFixed(1)}Cr`;
13→  if (abs >= 1_00_000) return `${(amount / 1_00_000).toFixed(1)}L`;
14→  if (abs >= 1_000) return `${(amount / 1_000).toFixed(0)}K`;
15→  return formatCurrency(amount);
16→};
17→
18→export const formatDate = (dateStr: string): string => format(parseISO(dateStr), 'MMM yyyy');
19→
20→export const formatDateFull = (dateStr: string): string => format(parseISO(dateStr), 'dd MMM yyyy');
