 77→            data={data}
 78→            cx="50%"
 79→            cy="50%"
 80→            outerRadius={isMobile ? 85 : 130}
 81→            innerRadius={isMobile ? 30 : 45}
 82→            dataKey="value"
 83→            labelLine={false}
 84→            label={renderLabel}
 85→          >
 86→            {data.map((_, index) => (
